var isOperator = /[\.\/вҢҝвҚҖВЁвҚЈ]/;
var isNiladic = /вҚ¬/;
var isFunction = /[\+вҲ’Г—Г·вҢҲвҢҠвҲЈвҚі\?вӢҶвҚҹв—Ӣ!вҢ№<вүӨ=>вүҘвү вүЎвүўвҲҲвҚ·вҲӘвҲ©вҲјвҲЁвҲ§вҚұвҚІвҚҙ,вҚӘвҢҪвҠ–вҚүвҶ‘вҶ“вҠӮвҠғвҢ·вҚӢвҚ’вҠӨвҠҘвҚ•вҚҺвҠЈвҠў]/;
var isArrow = /вҶҗ/;
var isComment = /[вҚқ#].*$/;

var stringEater = function(type) {
  var prev;
  prev = false;
  return function(c) {
    prev = c;
    if (c === type) {
      return prev === "\\";
    }
    return true;
  };
};

export const apl = {
  name: "apl",
  startState: function() {
    return {
      prev: false,
      func: false,
      op: false,
      string: false,
      escape: false
    };
  },
  token: function(stream, state) {
    var ch;
    if (stream.eatSpace()) {
      return null;
    }
    ch = stream.next();
    if (ch === '"' || ch === "'") {
      stream.eatWhile(stringEater(ch));
      stream.next();
      state.prev = true;
      return "string";
    }
    if (/[\[{\(]/.test(ch)) {
      state.prev = false;
      return null;
    }
    if (/[\]}\)]/.test(ch)) {
      state.prev = true;
      return null;
    }
    if (isNiladic.test(ch)) {
      state.prev = false;
      return "atom";
    }
    if (/[ВҜ\d]/.test(ch)) {
      if (state.func) {
        state.func = false;
        state.prev = false;
      } else {
        state.prev = true;
      }
      stream.eatWhile(/[\w\.]/);
      return "number";
    }
    if (isOperator.test(ch)) {
      return "operator"
    }
    if (isArrow.test(ch)) {
      return "operator";
    }
    if (isFunction.test(ch)) {
      state.func = true;
      state.prev = false;
      return builtInFuncs[ch] ? "variableName.function.standard" : "variableName.function"
    }
    if (isComment.test(ch)) {
      stream.skipToEnd();
      return "comment";
    }
    if (ch === "вҲҳ" && stream.peek() === ".") {
      stream.next();
      return "variableName.function";
    }
    stream.eatWhile(/[\w\$_]/);
    state.prev = true;
    return "keyword";
  }
}
